#include <stdio.h>
#include <stdint.h>

static uint64_t pow3(int exp) {
    uint64_t res = 1;
    for (int i = 0; i < exp; ++i) res *= 3ULL;
    return res;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N < 3) {
            printf("0\n");
        } else {
            uint64_t term = pow3(N - 3);
            uint64_t ans = (uint64_t)(N - 2) * 10ULL * term;
            printf("%llu\n", ans);
        }
    }
    return 0;
}

