code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static long pow3(int e) {
        long r = 1;
        for (int i = 0; i < e; i++) r *= 3L;
        return r;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine().trim());
            if (N < 3) sb.append(0);
            else {
                long ans = (long)(N - 2) * 10L * pow3(N - 3);
                sb.append(ans);
            }
            if (t + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def pow3(e: int) -> int:
    return 3 ** e

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        if N < 3:
            out.append('0')
        else:
            ans = (N - 2) * 10 * pow3(N - 3)
            out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

